<script lang="ts">
  import { resolve } from '$app/paths';
  import { onMount } from 'svelte';
  import { colord } from 'colord';
  import { Copy, RefreshCw, Palette, ExternalLink } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { i18n } from '$lib/i18n';
  import { ButtonIcon } from '$lib/components/ui';

  let currentColor = $state(colord('#3b82f6')); // fallback
  let hexString = $derived(currentColor.toHex());

  function generateRandomColor() {
    // Generate a random aesthetic color (avoiding too dark/too light)
    currentColor = colord({
      h: Math.floor(Math.random() * 360),
      s: 40 + Math.floor(Math.random() * 40), // 40-80%
      l: 50 + Math.floor(Math.random() * 30), // 50-80%
    });
  }

  onMount(() => {
    generateRandomColor();
  });
  let isLight = $derived(currentColor.isLight());
  let textClass = $derived(isLight ? 'text-gray-900' : 'text-white');
  let btnClass = $derived(isLight ? 'bg-white/50 hover:bg-white/70 text-gray-900' : 'bg-white/20 hover:bg-white/30 text-white/80 hover:text-white');
  let btnDarkClass = $derived(isLight ? 'bg-black/5 hover:bg-black/10 text-gray-800 hover:text-gray-900' : 'bg-black/10 hover:bg-black/20 text-white/80 hover:text-white');
  let borderClass = $derived(isLight ? 'border-gray-900/30' : 'border-white/60');
</script>

<div 
  class="relative bg-white dark:bg-gray-900 rounded-2xl border border-gray-200 dark:border-gray-800 p-4 shadow-sm h-full flex flex-col justify-between overflow-hidden group transition-colors duration-500"
  style="background-color: {hexString};"
>
  <!-- Background Pattern (Glassmorphism effect) -->
  <div class="absolute inset-0 opacity-20 pointer-events-none mix-blend-overlay" style="background-image: repeating-linear-gradient(45deg, transparent, transparent 10px, rgba(255,255,255,0.1) 10px, rgba(255,255,255,0.1) 20px);"></div>
  
  <div class="relative z-10 flex justify-between items-start mb-6">
    <h2 class="text-xs font-bold {textClass} uppercase tracking-wider flex items-center gap-1.5 drop-shadow-md transition-colors">
      <Palette class="w-3.5 h-3.5" /> {i18n.t('ui.tooltips.color.ofTheMoment')}
    </h2>
    <ButtonIcon 
      onclick={generateRandomColor}
      color="custom"
      class="{btnDarkClass} backdrop-blur-sm"
      title={i18n.t('ui.tooltips.color.generateNew')}
    >
      <RefreshCw class="w-3.5 h-3.5" />
    </ButtonIcon>
  </div>

  <div class="relative z-10 flex flex-col items-center justify-center py-2 flex-1">
    <div class="flex items-center gap-3">
      
      <!-- Native Color Picker Bubble -->
      <div class="relative w-8 h-8 rounded-full border-2 {borderClass} shadow-lg flex items-center justify-center transition-colors duration-300 overflow-hidden shrink-0 hover:scale-105">
        <input 
          type="color" 
          value={hexString}
          oninput={(e) => {
            const c = colord(e.currentTarget.value);
            if (c.isValid()) currentColor = c;
          }}
          class="absolute -inset-4 opacity-0 cursor-pointer w-[200%] h-[200%] z-20"
          title={i18n.t('ui.tooltips.color.pick')}
        />
        <div class="w-full h-full pointer-events-none mix-blend-overlay opacity-50 bg-white"></div>
        <div class="absolute inset-0 w-full h-full pointer-events-none" style="background-color: {hexString};"></div>
      </div>

      <!-- Editable HEX Text -->
      <input
        type="text"
        value={hexString}
        oninput={(e) => {
          const c = colord(e.currentTarget.value);
          if (c.isValid()) currentColor = c;
        }}
        onblur={(e) => {
          e.currentTarget.value = hexString;
        }}
        class="text-3xl font-black {textClass} drop-shadow-lg tracking-wider uppercase bg-transparent border-none p-0 focus:ring-0 w-[155px] text-center outline-none transition-colors"
        spellcheck="false"
        title={i18n.t('ui.tooltips.color.editHex')}
      />

      <ButtonIcon 
        onclick={() => copyText(hexString)}
        color="custom"
        class="{btnClass} !p-2 !rounded-xl backdrop-blur-md shadow-sm shrink-0"
        title={i18n.t('ui.tooltips.copy.hex')}
      >
        <Copy class="w-4 h-4" />
      </ButtonIcon>
    </div>
  </div>

  <div class="relative z-10 mt-4 flex justify-end">
    <a 
      href={resolve('/color')}
      class="flex items-center gap-1.5 text-[10px] font-bold {btnDarkClass} px-2.5 py-1.5 rounded-lg backdrop-blur-sm transition-all uppercase tracking-wider"
    >
      {i18n.t('ui.tooltips.color.openTools')} <ExternalLink class="w-3 h-3" />
    </a>
  </div>
</div>
