  import { i18n } from '$lib/i18n';

  let bgHex = $state('#1e293b'); // slate-800
  let fgHex = $state('#f8fafc'); // slate-50

  let ratio = $derived(colord(bgHex).contrast(colord(fgHex)).toFixed(1));
  let isPass = $derived(Number(ratio) >= 4.5);
