<script lang="ts">
  import { resolve } from '$app/paths';
  import { Droplet, ExternalLink } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { i18n } from '$lib/i18n';

  // Sample trending palettes
  const palettes = [
    { name: 'Emerald', colors: ['#ecfdf5', '#a7f3d0', '#34d399', '#059669', '#064e3b'] },
    { name: 'Rose', colors: ['#fff1f2', '#fecdd3', '#fb7185', '#e11d48', '#881337'] },
    { name: 'Violet', colors: ['#f5f3ff', '#ddd6fe', '#a78bfa', '#7c3aed', '#4c1d95'] },
    { name: 'Amber', colors: ['#fffbeb', '#fde68a', '#fbbf24', '#d97706', '#78350f'] },
    { name: 'Sky', colors: ['#f0f9ff', '#bae6fd', '#38bdf8', '#0284c7', '#0c4a6e'] },
  ];

  // Pick a random palette on load
  let activePalette = $state(palettes[Math.floor(Math.random() * palettes.length)]);

</script>

<div class="bg-white dark:bg-gray-900 rounded-2xl border border-gray-200 dark:border-gray-800 p-4 shadow-sm h-full flex flex-col justify-between">
  <div class="flex justify-between items-center mb-3">
    <h3 class="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase tracking-wider flex items-center gap-1.5">
      <Droplet class="w-3.5 h-3.5 text-blue-500" /> Palette: {activePalette.name}
    </h3>
    <a 
      href={resolve('/color')}
      class="text-gray-400 hover:text-blue-500 transition-colors"
      title={i18n.t('ui.tooltips.color.openTools')}
    >
      <ExternalLink class="w-3.5 h-3.5" />
    </a>
  </div>

  <div class="flex-1 flex flex-col gap-1 rounded-lg overflow-hidden border border-gray-100 dark:border-gray-800">
    {#each activePalette.colors as color (color)}
      <!-- svelte-ignore a11y_click_events_have_key_events -->
      <!-- svelte-ignore a11y_no_static_element_interactions -->
      <div 
        class="flex-1 flex items-center justify-center cursor-pointer group hover:flex-[1.5] transition-all duration-300 relative"
        style="background-color: {color};"
        onclick={() => copyText(color)}
        title="{i18n.t('common.copy')} {color}"
      >
        <span class="text-[10px] font-bold text-white mix-blend-difference opacity-0 group-hover:opacity-100 transition-opacity bg-black/20 px-2 py-0.5 rounded">
          {color}
        </span>
      </div>
    {/each}
  </div>
</div>
