<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { detectFormat, type DetectedFormat } from '$lib/utils/detector';
  import { Sparkles, ArrowRight, Wand2 } from 'lucide-svelte';
  import { tools, TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';
  import type { ToolDefinition } from '$lib/types';
  import { smartInputState } from '$lib/utils/smartInput';
  import { settingsStore } from '$lib/stores/settings.svelte';
  import { goto } from '$app/navigation';

  let rawInput = $state('');
  let detectedFormats = $state<DetectedFormat[]>([]);
  let isAnalyzing = $state(false);
  let isDragging = $state(false);
  
  // Variable to store timeout ID for Debounce
  let debounceTimer: ReturnType<typeof setTimeout>;

  // Listen to changes in rawInput for analysis
  $effect(() => {
    const currentInput = rawInput; // Trigger reactivity
    
    // Clear previous timeout if user is typing continuously
    clearTimeout(debounceTimer);

    if (!currentInput.trim()) {
      detectedFormats = [];
      isAnalyzing = false;
      return;
    }

    isAnalyzing = true;

    // Wait 300ms after user stops typing/pasting to start analysis
    debounceTimer = setTimeout(() => {
      // Call detect function (Analysis Brain) if autoSuggest is enabled
      if (settingsStore.config.smartInput.autoSuggest) {
        detectedFormats = detectFormat(currentInput);
      } else {
        detectedFormats = [];
      }
      isAnalyzing = false;
    }, 300);
  });

  // Dynamically build suggestion map based on tools' acceptsFormats
  let dynamicSuggestionMap = $derived.by(() => {
    const map: Record<string, ToolDefinition[]> = {};
    tools.forEach(tool => {
      if (tool.acceptsFormats) {
        tool.acceptsFormats.forEach(format => {
          if (!map[format]) map[format] = [];
          map[format].push(tool);
        });
      }
    });
    return map;
  });

  function handleToolClick(slug: string) {
    // Store data globally and redirect
    smartInputState.text = rawInput;
    goto(`/${slug}`);
  }

  function handleKeyDown(e: KeyboardEvent) {
    // Shortcut: Ctrl+Enter or Cmd+Enter to auto-select the first suggestion
    if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
      if (!settingsStore.config.smartInput.cmdEnterToRun) return; // Respect config

      if (detectedFormats.length > 0) {
        // If there's a suggested format, run the first tool for that format
        const firstFormat = detectedFormats.find(f => f !== null);
        if (firstFormat && dynamicSuggestionMap[firstFormat] && dynamicSuggestionMap[firstFormat].length > 0) {
          e.preventDefault();
          const firstTool = dynamicSuggestionMap[firstFormat][0];
          handleToolClick(firstTool.slug);
        }
      }
    }
  }

  function handleDrop(e: DragEvent) {
    e.preventDefault();
    isDragging = false;
    if (e.dataTransfer && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
          rawInput = event.target.result as string;
        }
      };
      reader.readAsText(file);
    }
  }

  function clearInput() {
    rawInput = '';
  }
</script>

<div class="w-full max-w-4xl mx-auto flex flex-col gap-4 relative z-30">
  
  <!-- Container with Drag & Drop events and Glow Focus -->
  <!-- svelte-ignore a11y_no_static_element_interactions -->
  <div 
    class="relative group rounded-2xl border-2 shadow-sm transition-all overflow-hidden flex flex-col focus-within:border-blue-500 dark:focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-500/20 {isDragging ? 'border-blue-500 bg-blue-50/50 dark:bg-blue-900/20 scale-[1.02]' : 'border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900'}"
    ondragover={(e) => { e.preventDefault(); isDragging = true; }}
    ondragleave={() => isDragging = false}
    ondrop={handleDrop}
  >
    
    <div class="flex items-center justify-between px-4 py-3 bg-gray-50/50 dark:bg-gray-800/30 border-b border-gray-100 dark:border-gray-800">
      <div class="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-300">
        {#if isAnalyzing}
          <div class="w-4 h-4 rounded-full border-2 border-blue-500 border-t-transparent animate-spin"></div>
          <span>Analyzing...</span>
        {:else}
          <Sparkles class="w-4 h-4 text-blue-500" />
          <span>Smart Gateway</span>
        {/if}
      </div>

      {#if rawInput}
        <button 
          onclick={clearInput}
          class="text-xs font-medium text-gray-500 hover:text-red-500 transition-colors"
        >
          Clear
        </button>
      {/if}
    </div>

    <div class="relative w-full h-40">
      <!-- Watermark when empty -->
      {#if !rawInput && !isDragging}
        <div class="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.03] dark:opacity-[0.05] transition-opacity">
          <Wand2 class="w-24 h-24 text-gray-900 dark:text-white" />
        </div>
      {/if}

      <!-- Dragging Overlay Text -->
      {#if isDragging}
        <div class="absolute inset-0 flex items-center justify-center pointer-events-none bg-white/50 dark:bg-gray-900/50 backdrop-blur-sm z-10">
          <span class="text-xl font-bold text-blue-500 animate-pulse">Drop file here to read...</span>
        </div>
      {/if}

      <textarea
        bind:value={rawInput}
        onkeydown={handleKeyDown}
        placeholder={i18n.t('ui.placeholders.smartInput')}
        class="absolute inset-0 w-full h-full p-4 bg-transparent resize-none outline-none text-gray-800 dark:text-gray-200 font-mono text-sm custom-scrollbar z-0"
        spellcheck="false"
      ></textarea>

      <!-- Loading State for Analysis -->
      {#if isAnalyzing && settingsStore.config.smartInput.autoSuggest}
        <div class="absolute right-3 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg text-xs font-semibold flex items-center gap-2 animate-pulse">
          <Wand2 class="w-3.5 h-3.5" />
          Analyzing...
        </div>
      {/if}

      <!-- Keyboard Shortcut Hint -->
      {#if rawInput && detectedFormats.length > 0}
        <div class="absolute bottom-3 right-4 pointer-events-none flex items-center gap-2 opacity-40 group-focus-within:opacity-100 transition-opacity">
          <span class="text-[10px] font-medium text-gray-500 uppercase tracking-wide">Auto-Run</span>
          <div class="flex items-center gap-1">
            <kbd class="px-1.5 py-0.5 bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-[10px] font-bold text-gray-600 dark:text-gray-400">Cmd</kbd>
            <kbd class="px-1.5 py-0.5 bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-[10px] font-bold text-gray-600 dark:text-gray-400">↵</kbd>
          </div>
        </div>
      {/if}
    </div>
  </div>

  {#if detectedFormats.length > 0}
    <!-- Absolute popover over UI -->
    <div class="absolute top-[105%] left-0 right-0 bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl rounded-2xl border border-gray-200 dark:border-gray-800 shadow-2xl p-5 flex flex-col gap-4 animate-in slide-in-from-top-2 fade-in duration-200 z-50">
      <h3 class="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider px-1">
        Suggested Tools
      </h3>
      
      <div class="grid grid-cols-1 sm:grid-cols-2 gap-3">
        {#each detectedFormats as format (format)}
          {#if format && dynamicSuggestionMap[format]}
            {#each dynamicSuggestionMap[format] as tool (tool.id)}
              {@const ToolIcon = TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon}
              <button 
                onclick={() => handleToolClick(tool.slug)}
                class="flex w-full text-left items-center justify-between p-3 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-transparent hover:border-blue-300 dark:hover:border-blue-700 hover:bg-white dark:hover:bg-gray-800 hover:shadow-md transition-all group cursor-pointer"
              >
                <div class="flex items-center gap-3 min-w-0 flex-1">
                  <div class="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg group-hover:scale-110 transition-transform shrink-0">
                    <ToolIcon class="w-4 h-4" />
                  </div>
                  <span class="font-medium text-gray-800 dark:text-gray-200 text-sm truncate flex-1">{i18n.t(tool.name) || tool.name}</span>
                </div>
                <ArrowRight class="w-4 h-4 text-gray-300 dark:text-gray-600 group-hover:text-blue-500 transition-colors group-hover:translate-x-1 shrink-0" />
              </button>
            {/each}
          {/if}
        {/each}
      </div>
    </div>
  {/if}

</div>