<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { copyText } from '$lib/utils/clipboard';

  import { getFormattedDate, getDatetimeLocalString, convertDateOrTimestamp } from '$lib/utils/date';
  import { Separator, Popover, ButtonIcon } from '$lib/components/ui';

  import { Copy, Clock, ChevronsDown, ArrowRightLeft, CalendarDays, Hash } from 'lucide-svelte';
  import { fly } from 'svelte/transition';

  // Mode Status:
  //    - decode: Timestamp -> Date
  //    - encode: Date -> Timestamp
  let mode = $state<'decode' | 'encode'>('decode');
  let selectedTimezone = $state<string>('local');
  
  const initialDate = new Date();

  let now = $state(initialDate);
  let currentUnixTime = $derived(Math.floor(now.getTime() / 1000));
  let formattedDate = $derived(getFormattedDate(now, i18n.locale));

  let decodeInput = $state(Math.floor(initialDate.getTime() / 1000).toString());
  let encodeInput = $state(getDatetimeLocalString(initialDate));

  // Live Timer (Safe, no RAM leak thanks to cleanup function)
  $effect(() => {
    const timer = setInterval(() => {
      now = new Date();
    }, 1000);
    return () => clearInterval(timer);
  });

  // Auto-fill current time based on mode
  function handleQuickFill() {
    if (mode === 'decode') {
      decodeInput = currentUnixTime.toString();
    } else {
      encodeInput = getDatetimeLocalString(new Date());
    }
  }

  let result = $derived(
    convertDateOrTimestamp(
      mode,
      mode === 'decode' ? decodeInput : encodeInput,
      selectedTimezone,
      i18n.locale,
      i18n.t('page.widget.invalidFormat')
    )
  );
</script>

<div class="bg-white dark:bg-gray-900 border-2 border-gray-200 dark:border-gray-800 focus-within:border-blue-500 dark:focus-within:border-blue-500 rounded-2xl shadow-sm flex flex-col transition-all duration-200 h-full">
  
  <div class="flex items-center justify-between px-4 py-3 bg-gray-50/50 dark:bg-gray-800/30 border-b border-gray-100 dark:border-gray-800 rounded-t-xl transition-colors">
    <div class="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-300">

      <Popover position="bottom" align="start" contentClass="p-2 whitespace-nowrap">
        <Clock class="w-4 h-4 text-blue-600 dark:text-blue-400 animate-pulse hidden sm:block cursor-help" />
        {#snippet content()}
          <div class="flex items-center justify-between w-full gap-3 cursor-default font-mono">
            <div class="flex items-center gap-1.5">
              <span>{formattedDate}</span>
              <span class="px-1.5 py-0.5 rounded bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 tracking-wide text-[9px] font-bold font-sans uppercase">
                {i18n.t('common.time.localTime') || 'Local Time'}
              </span>
            </div>
          </div>
        {/snippet}
      </Popover>

      <span class="truncate">{mode === 'decode' ? (i18n.t('page.widget.liveEpoch') || 'Live Epoch') : (i18n.t('page.widget.liveTime') || 'Live Time')}</span>
    </div>

    <div class="flex items-center gap-2 group">
      <ButtonIcon 
        onclick={handleQuickFill}
        color="blue"
        class="opacity-0 group-hover:opacity-100"
        title="{i18n.t('page.widget.autoFillText')}"
      >
        <ChevronsDown class="w-4 h-4" />
      </ButtonIcon>
      <!-- Live Clock Display (Clickable text to copy) -->
      <button 
        onclick={() => copyText(mode === 'decode' ? currentUnixTime.toString() : formattedDate)} 
        class="flex items-center text-lg sm:text-xl font-mono font-bold text-gray-900 dark:text-gray-100 tracking-tight hover:text-blue-600 dark:hover:text-blue-400 transition-colors truncate max-w-[150px] sm:max-w-[250px]"
        title="{i18n.t('common.copy')}"
      >
        <span class="truncate">{mode === 'decode' ? currentUnixTime : formattedDate}</span>
      </button>
    </div>
  </div>

  <div class="p-4 sm:p-5 flex-1 flex flex-col justify-center gap-4">

    <div class="flex flex-col gap-3">
      <div class="w-full">
        <div class="flex items-center h-[42px] w-full rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50 focus-within:ring-2 focus-within:ring-blue-500/20 dark:focus-within:ring-blue-500/30 focus-within:border-blue-500 transition-colors shadow-sm overflow-hidden">
          
          <button 
            onclick={() => mode = mode === 'decode' ? 'encode' : 'decode'}
            class="flex items-center justify-center h-full px-3.5 bg-gray-100/80 dark:bg-gray-800/80 hover:bg-gray-200 dark:hover:bg-gray-700/80 border-r border-gray-200 dark:border-gray-700 text-[13px] font-bold text-gray-700 dark:text-gray-300 transition-colors shrink-0 group/btn overflow-hidden"
            title="Toggle mode"
          >
            <ArrowRightLeft class="w-3.5 h-3.5 mr-1.5 shrink-0 text-gray-400 group-hover/btn:text-blue-500 transition-transform duration-300 {mode === 'encode' ? '-rotate-180' : ''}" />
            <div class="grid [grid-template-areas:'stack'] place-items-center">
              <span class="[grid-area:stack] invisible pointer-events-none" aria-hidden="true">{i18n.t('common.time.timestamp') || 'Timestamp'}</span>
              <span class="[grid-area:stack] invisible pointer-events-none" aria-hidden="true">{i18n.t('common.time.datetime') || 'Datetime'}</span>
              {#if mode === 'decode'}
                <span in:fly={{ y: 15, duration: 250, delay: 100 }} out:fly={{ y: -15, duration: 250 }} class="[grid-area:stack]">
                  {i18n.t('common.time.timestamp') || 'Timestamp'}
                </span>
              {:else}
                <span in:fly={{ y: 15, duration: 250, delay: 100 }} out:fly={{ y: -15, duration: 250 }} class="[grid-area:stack]">
                  {i18n.t('common.time.datetime') || 'Datetime'}
                </span>
              {/if}
            </div>
          </button>

          <div class="grid [grid-template-areas:'stack'] flex-1 h-full overflow-hidden">
            {#if mode === 'decode'}
              <div in:fly={{ y: 15, duration: 250, delay: 100 }} out:fly={{ y: -15, duration: 250 }} class="[grid-area:stack] relative w-full h-full group/input flex">
                <div class="absolute inset-y-0 left-0 flex items-center pl-3.5 pointer-events-none text-gray-400 group-focus-within/input:text-blue-500 transition-colors">
                  <Hash class="w-4 h-4" />
                </div>
                <input 
                  type="text"
                  bind:value={decodeInput}
                  placeholder={i18n.t('page.widget.datePlaceholder')}
                  class="w-full h-full pl-10 pr-4 bg-transparent text-sm text-gray-900 dark:text-gray-100 placeholder:text-gray-400 dark:placeholder:text-gray-500 outline-none ring-0 border-0"
                >
              </div>
            {:else}
              <div in:fly={{ y: 15, duration: 250, delay: 100 }} out:fly={{ y: -15, duration: 250 }} class="[grid-area:stack] relative w-full h-full min-w-0 group/input flex">
                <div class="absolute inset-y-0 left-0 flex items-center pl-3.5 pointer-events-none text-gray-400 group-focus-within/input:text-blue-500 transition-colors z-10">
                  <CalendarDays class="w-4 h-4" />
                </div>
                <input 
                  type="datetime-local"
                  step="1"
                  bind:value={encodeInput}
                  class="[&::-webkit-calendar-picker-indicator]:opacity-0 [&::-webkit-calendar-picker-indicator]:absolute [&::-webkit-calendar-picker-indicator]:top-0 [&::-webkit-calendar-picker-indicator]:left-0 [&::-webkit-calendar-picker-indicator]:w-full [&::-webkit-calendar-picker-indicator]:h-full [&::-webkit-calendar-picker-indicator]:cursor-pointer relative z-0 w-full h-full pl-10 pr-4 bg-transparent text-sm text-gray-900 dark:text-gray-100 outline-none ring-0 border-0 cursor-pointer"
                >
              </div>
            {/if}
          </div>

          <div class="relative shrink-0 h-full border-l border-gray-200 dark:border-gray-700 bg-gray-100/80 dark:bg-gray-800/80">
            <select 
              bind:value={selectedTimezone}
              aria-label={i18n.t('common.time.timezone') || 'Select timezone'}
              title={i18n.t('common.time.timezone') || 'Select timezone'}
              class="w-[88px] h-full px-2 bg-transparent text-xs font-bold text-gray-600 dark:text-gray-300 outline-none ring-0 cursor-pointer appearance-none text-center tracking-wide uppercase"
            >
              <option value="local">{i18n.t('common.time.local') || 'Local'}</option>
              <option value="gmt">{i18n.t('common.time.utc') || 'UTC'}</option>
              <option value="-12">GMT-12</option>
              <option value="-11">GMT-11</option>
              <option value="-10">GMT-10</option>
              <option value="-9">GMT-9</option>
              <option value="-8">GMT-8</option>
              <option value="-7">GMT-7</option>
              <option value="-6">GMT-6</option>
              <option value="-5">GMT-5</option>
              <option value="-4">GMT-4</option>
              <option value="-3">GMT-3</option>
              <option value="-2">GMT-2</option>
              <option value="-1">GMT-1</option>
              <option value="+1">GMT+1</option>
              <option value="+2">GMT+2</option>
              <option value="+3">GMT+3</option>
              <option value="+4">GMT+4</option>
              <option value="+5">GMT+5</option>
              <option value="+6">GMT+6</option>
              <option value="+7">GMT+7</option>
              <option value="+8">GMT+8</option>
              <option value="+9">GMT+9</option>
              <option value="+10">GMT+10</option>
              <option value="+11">GMT+11</option>
              <option value="+12">GMT+12</option>
              <option value="+13">GMT+13</option>
              <option value="+14">GMT+14</option>
            </select>
          </div>
        </div>
      </div>

      <div class="w-full">
        {#if !result}
          <div class="h-[42px] px-4 rounded-xl border border-dashed border-gray-200 dark:border-gray-700 bg-gray-50/50 dark:bg-gray-900/30 flex items-center text-sm text-gray-500 dark:text-gray-400 transition-colors">
            ...
          </div>
        {:else if result.type === 'error'}
          <div class="h-[42px] px-4 rounded-xl border border-red-200 dark:border-red-900/50 bg-red-50 dark:bg-red-950/20 flex items-center text-sm text-red-500 dark:text-red-400 transition-colors">
            {result.value}
          </div>
        {:else}
          <Popover 
            position="bottom" 
            align="end" 
            contentClass="w-[300px] sm:w-[340px] max-w-[85vw] p-3 text-left flex flex-col gap-1.5 cursor-default" 
            delay={200}
            disabled={!result.tooltip}
            wrapperClass="block w-full"
          >
            <button 
              onclick={() => copyText(result?.value || '')}
              title={i18n.t('common.copy')}
              class="w-full h-[42px] px-4 rounded-xl border border-green-200 dark:border-green-900/50 bg-green-50 dark:bg-green-950/20 flex items-center justify-between hover:bg-green-100 dark:hover:bg-green-900/40 hover:border-green-300 dark:hover:border-green-700 transition-all cursor-pointer group/btn"
            >
              <div class="flex items-baseline gap-2 truncate pr-2">
                <span class="text-sm font-bold text-green-700 dark:text-green-400 group-hover/btn:text-green-800 dark:group-hover/btn:text-green-300 transition-colors">
                  {result.value}
                </span>
                {#if result.hint}
                  <span class="text-xs font-medium text-green-700 dark:text-green-400 hidden sm:inline-block">
                    {result.hint}
                  </span>
                {/if}
              </div>

              <div class="text-green-600/50 dark:text-green-500/50 group-hover/btn:text-green-700 dark:group-hover/btn:text-green-400 transition-colors shrink-0">
                <Copy class="w-4 h-4" />
              </div>
            </button>

            {#snippet content()}
              {#if result.tooltip}
                <div class="group/row flex items-center hover:bg-gray-100 dark:hover:bg-gray-700/50 px-2 py-1 rounded-lg transition-colors">
                  <span class="w-20 sm:w-24 shrink-0 px-1 py-0.5 rounded bg-gray-200/50 dark:bg-gray-700 text-[10px] sm:text-[11px] text-gray-600 dark:text-gray-400 font-bold tracking-wider text-center whitespace-nowrap">
                    {i18n.t('common.time.utc') || 'UTC'}
                  </span>
                  <button class="flex-1 text-left text-[11px] sm:text-xs font-medium text-gray-700 dark:text-gray-200 truncate px-3 cursor-pointer" onclick={() => copyText(result?.tooltip?.gmt || '')}>
                    {result.tooltip?.gmt}
                  </button>
                  <ButtonIcon onclick={() => copyText(result?.tooltip?.gmt || '')} color="blue" class="shrink-0 opacity-0 group-hover/row:opacity-100">
                    <Copy class="w-3.5 h-3.5" />
                  </ButtonIcon>
                </div>

                <div class="group/row flex items-center hover:bg-gray-100 dark:hover:bg-gray-700/50 px-2 py-1 rounded-lg transition-colors">
                  <span class="w-20 sm:w-24 shrink-0 px-1 py-0.5 rounded bg-blue-100 dark:bg-blue-900/40 text-[10px] sm:text-[11px] text-blue-600 dark:text-blue-400 font-bold tracking-wider text-center whitespace-nowrap">
                    {i18n.t('common.time.localTime') || 'Local Time'}
                  </span>
                  <button class="flex-1 text-left text-[11px] sm:text-xs font-medium text-gray-700 dark:text-gray-200 truncate px-3 cursor-pointer" onclick={() => copyText(result?.tooltip?.local || '')}>
                    {result.tooltip?.local}
                  </button>
                  <ButtonIcon onclick={() => copyText(result?.tooltip?.local || '')} color="blue" class="shrink-0 opacity-0 group-hover/row:opacity-100">
                    <Copy class="w-3.5 h-3.5" />
                  </ButtonIcon>
                </div>

                {#if result.tooltip?.userSelected}
                  <div class="group/row flex items-center hover:bg-gray-100 dark:hover:bg-gray-700/50 px-2 py-1 rounded-lg transition-colors">
                    <span class="w-20 sm:w-24 shrink-0 px-1 py-0.5 rounded bg-purple-100 dark:bg-purple-900/40 text-[10px] sm:text-[11px] text-purple-600 dark:text-purple-400 font-bold tracking-wider text-center whitespace-nowrap">
                      {result.tooltip.userSelected.label}
                    </span>
                    <button class="flex-1 text-left text-[11px] sm:text-xs font-medium text-gray-700 dark:text-gray-200 truncate px-3 cursor-pointer" onclick={() => copyText(result?.tooltip?.userSelected?.value || '')}>
                      {result.tooltip.userSelected.value}
                    </button>
                    <ButtonIcon onclick={() => copyText(result?.tooltip?.userSelected?.value || '')} color="blue" class="shrink-0 opacity-0 group-hover/row:opacity-100">
                      <Copy class="w-3.5 h-3.5" />
                    </ButtonIcon>
                  </div>
                {/if}

                <Separator class="my-1" />

                <div class="flex items-center justify-center gap-1.5 px-2 py-1">
                  <Clock class="w-3.5 h-3.5 text-blue-500" />

                  <span class="text-xs sm:text-sm font-semibold text-blue-600 dark:text-blue-400 truncate">
                    {result.tooltip?.relative}
                  </span>
                </div>
              {/if}
            {/snippet}
          </Popover>
        {/if}
      </div>
    </div>
  </div>
</div>