<script lang="ts">
  import { flip } from 'svelte/animate';
  import { fade, scale } from 'svelte/transition';
  import { quintOut } from 'svelte/easing';
  import { i18n } from '$lib/i18n';
  import { tools, getStructuredCategories, getToolsByCategoryId } from '$lib/registry';
  import type { ToolDefinition } from '$lib/types';
  import { SmartInput, DateConvert, ColorWidgetContainer } from '$lib/components/widget';
  import { ToolCard, Separator, FilterTab } from '$lib/components/ui';
  import { favoritesStore } from '$lib/stores/favorites.svelte';
  import { recentStore } from '$lib/stores/recent.svelte';

  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';
  import { Star, Clock } from 'lucide-svelte';
  import { Button } from '$lib/components/ui';

  let activeCategoryId = $state<string>('all');

  let categories = $derived(getStructuredCategories());

  let displayTools = $derived.by(() => {
    let rawTools = tools;
    if (activeCategoryId === 'favorites') {
      rawTools = tools.filter((t) => favoritesStore.has(t.id));
    } else if (activeCategoryId === 'recent') {
      // Keep the sort order of recentStore.items
      rawTools = recentStore.items.map(id => tools.find(t => t.id === id)).filter(Boolean) as ToolDefinition[];
    } else if (activeCategoryId !== 'all') {
      rawTools = getToolsByCategoryId(activeCategoryId);
    }
    
    return rawTools.map((tool: ToolDefinition) => ({
      ...tool,
      Icon: TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon,
      translatedName: i18n.t(tool.name),
      translatedDesc: i18n.t(tool.description || '')
    }));
  });
</script>

<div class="mx-auto">
  <!-- HEADER -->
  <header class="mb-8 flex flex-col md:flex-row md:items-start justify-between gap-4 md:gap-8">
    <div class="flex-1 md:w-[80%] min-w-0">
      <h1 title={i18n.t('app.title')} class="text-3xl font-bold tracking-tight text-gray-900 dark:text-gray-100 truncate cursor-default">
        Debox - 
        <span class="bg-gradient-to-br from-red-600 to-orange-500 dark:from-red-500 dark:to-orange-400 text-transparent bg-clip-text">H</span>andy 
        <span class="bg-gradient-to-br from-orange-500 to-amber-500 dark:from-orange-400 dark:to-amber-400 text-transparent bg-clip-text">U</span>tility 
        <span class="bg-gradient-to-br from-amber-500 to-yellow-500 dark:from-amber-400 dark:to-yellow-400 text-transparent bg-clip-text">B</span>ox
      </h1>
      <p class="text-gray-500 dark:text-gray-400 mt-1 truncate">{i18n.t('app.description.home')}</p>
    </div>
    <div class="flex items-center gap-3 shrink-0 md:w-[20%] justify-end">

      <Button 
        href="https://github.com/zeforc/deboxhub" 
        target="_blank" 
        color="gray"
        size="sm"
        class="shadow-sm font-medium"
      >
        <Star class="w-4 h-4 fill-current mr-1.5" />
        Star on GitHub
      </Button>
    </div>
  </header>

  <section class="space-y-8">
  
    <div class="grid grid-cols-1 lg:grid-cols-[33%_39%_1fr] gap-6 items-stretch">

      <!-- COL 1: Quick Parse -->
      <div class="flex flex-col">
        <SmartInput />
      </div>

      <!-- COL 2: Date Convert -->
      <div class="flex flex-col">
        <DateConvert />
      </div>

      <!-- COL 3: Color Widget -->
      <div class="flex flex-col">
        <ColorWidgetContainer />
      </div>

    </div>

    <div class="grid grid-cols-1 lg:grid-cols-4 gap-8 items-start">

      <!-- Left Col (25%): Sidebar Widgets -->
      <div class="lg:col-span-1 lg:sticky lg:top-6 flex flex-col gap-6">
        
        <!-- Placeholder for future widgets -->
        <div class="bg-white/40 dark:bg-gray-900/40 rounded-2xl border-2 border-dashed border-gray-200 dark:border-gray-800 p-8 flex flex-col items-center justify-center text-center h-[300px]">
          <div class="w-10 h-10 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center mb-3">
            <Star class="w-5 h-5 text-gray-400 dark:text-gray-500" />
          </div>
          <h3 class="text-sm font-bold text-gray-700 dark:text-gray-300 mb-1">Space for Widgets</h3>
          <p class="text-xs text-gray-600 dark:text-gray-400">Add settings, ads, or quick tools here.</p>
        </div>

      </div>

      <!-- Right Col (75%): TABS & GRID -->
      <div class="lg:col-span-3 space-y-4 mt-2">
        
        <Separator class="mb-6 opacity-70" />

        <div class="flex items-center gap-2 overflow-x-auto pb-2 custom-scrollbar">
          <FilterTab
            color="amber"
            variant="soft"
            inactiveVariant="outline"
            active={activeCategoryId === 'favorites'}
            onclick={() => activeCategoryId = 'favorites'}
          >
            <Star class="w-3.5 h-3.5 {activeCategoryId === 'favorites' ? 'fill-current' : ''}" /> {i18n.t('common.favorites')}
          </FilterTab>

          <FilterTab
            color="blue"
            variant="soft"
            inactiveVariant="outline"
            active={activeCategoryId === 'recent'}
            onclick={() => activeCategoryId = 'recent'}
          >
            <Clock class="w-3.5 h-3.5" /> {i18n.t('common.recent')}
          </FilterTab>

          <Separator orientation="vertical" size="6" class="mx-1 h-6 opacity-70" />

          <FilterTab
            inactiveVariant="solid"
            active={activeCategoryId === 'all'}
            onclick={() => activeCategoryId = 'all'}
          >
            {i18n.t('common.all')} ({tools.length})
          </FilterTab>

          {#each categories as category (category.id)}
            <FilterTab
              inactiveVariant="ghost"
              active={activeCategoryId === category.id}
              onclick={() => activeCategoryId = category.id}
            >
              {i18n.t(category.name) || category.name}
            </FilterTab>
          {/each}
        </div>

        {#if displayTools.length === 0}
          <div class="p-12 text-center bg-gray-50 dark:bg-gray-800/50 border border-dashed border-gray-200 dark:border-gray-700 rounded-2xl">
            <p class="text-gray-500 dark:text-gray-400">{i18n.t('error.searchNotFound')}</p>
          </div>
        {:else}
          <div class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-5">
            {#each displayTools as tool (tool.id)}
              <div
                animate:flip={{ duration: 300 }}
                in:scale={{ duration: 300, start: 0.95, easing: quintOut }}
                out:fade={{ duration: 400 }}
              >
                <ToolCard
                  id={tool.id}
                  href={tool.slug} 
                  icon={tool.Icon}
                  name={tool.translatedName}
                  description={tool.translatedDesc}
                  hideRecentIcon={activeCategoryId === 'recent'}
                />
              </div>
            {/each}
          </div>
        {/if}
      </div>

    </div>
  </section>
</div>