export type DetectedFormat = 'json' | 'html' | 'url' | 'base64' | 'jwt' | 'text' | null;

export function detectFormat(input: string): DetectedFormat[] {
  if (!input || !input.trim()) return [];
  
  const text = input.trim();
  const formats: Set<DetectedFormat> = new Set();

  // Check JWT (JSON Web Token)
  // Structure: 3 parts separated by dots, only base64url chars
  if (/^[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+\.[A-Za-z0-9-_]*$/.test(text)) {
    formats.add('jwt');
  }

  // Check URL
  try {
    new URL(text);
    formats.add('url');
  } catch {
    // Fallback to URL check
  }

  // Check JSON
  // Only try to parse if there are signs of JSON to save CPU
  if (text.startsWith('{') || text.startsWith('[')) {
    try {
      JSON.parse(text);
      formats.add('json');
    } catch {
        // Fallback to JSON check
    }
  }

  // Check HTML/XML
  // Cut first 1000 characters to avoid hanging if string is too long
  const sampleText = text.slice(0, 1000);
  if (/<\/?[a-z][\s\S]*>/i.test(sampleText)) {
    formats.add('html');
  }

  // Check Base64
  // String must be longer than 16 characters (avoid confusing with plain text), divisible by 4 and match charset
  if (
    text.length > 16 && 
    text.length % 4 === 0 && 
    /^[A-Za-z0-9+/]+={0,2}$/.test(text)
  ) {
    formats.add('base64');
  }

  // If nothing is recognized, it's plain text
  if (formats.size === 0) {
    formats.add('text');
  }

  return Array.from(formats);
}